  describe('state invariants (stateful PBT)', () => {
    it('always: valid lifecycle status', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('open'), input: fc.record({ pane: fc.string(), title: fc.string({ minLength: 1, maxLength: 50 }), hostRef: fc.string({ minLength: 1, maxLength: 50 }), icon: fc.string() }) }),
              fc.record({ action: fc.constant('close'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('minimize'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('maximize'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('restore'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('pin'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('unpin'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('setConstraints'), input: fc.record({ pane: fc.string(), minWidth: fc.string(), minHeight: fc.string(), preferredWidth: fc.string(), preferredHeight: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = paneHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(paneHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: closed pane is pinned', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('open'), input: fc.record({ pane: fc.string(), title: fc.string({ minLength: 1, maxLength: 50 }), hostRef: fc.string({ minLength: 1, maxLength: 50 }), icon: fc.string() }) }),
              fc.record({ action: fc.constant('close'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('minimize'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('maximize'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('restore'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('pin'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('unpin'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('setConstraints'), input: fc.record({ pane: fc.string(), minWidth: fc.string(), minHeight: fc.string(), preferredWidth: fc.string(), preferredHeight: fc.string() }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ pane: fc.string() }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = paneHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(paneHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: closed pane is pinned
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

